const input = $input.first()?.json?.body || $input.first()?.json || {};
const topic_id = String(input.topic_id || '');
const image_prompts = input.image_prompts || [];

if (!image_prompts || image_prompts.length === 0) {
  return [{ json: { error: 'No image_prompts provided', topic_id }];
}

const items = image_prompts.map((img, index) => ({
  json: {
    position: img.position || 'body_' + (index + 1),
    prompt: img.prompt,
    after_section: img.after_section || null,
    topic_id: topic_id
  }
}));

console.log('Procesando ' + items.length + ' imágenes para topic ' + topic_id);
return items;

