const response = $input.item.json;
const currentItem = $('Loop Imágenes').item.json;
const token = '***REMOVED-SECRET***';

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function getPrediction(url) {
  const res = await fetch(url, { headers: { Authorization: 'Bearer ' + token } });
  return res.json();
}

let cur = response;
for (let i = 0; i < 30; i++) {
  if (cur?.error) throw new Error('Replicate: ' + cur.error);
  if (cur?.status === 'failed' || cur?.status === 'canceled') throw new Error('Replicate ' + cur.status);
  if (cur?.status === 'succeeded' && cur?.output) {
    const imageUrl = Array.isArray(cur.output) ? cur.output[0] : cur.output;
    await sleep(2000);
    return [{ json: {
      position: currentItem.position,
      prompt: currentItem.prompt,
      after_section: currentItem.after_section,
      topic_id: currentItem.topic_id,
      imageUrl,
      provider: 'replicate'
    } }];
  }
  const pollUrl = cur?.urls?.get;
  if (!pollUrl) throw new Error('Sin poll URL');
  await sleep(4000);
  cur = await getPrediction(pollUrl);
}
throw new Error('Replicate timeout');

const item = $input.item;
const position = item.json.position || 'image';
const topic_id = item.json.topic_id || 'unknown';

if (item.binary?.data) {
  item.binary.data.fileName = position + '-' + topic_id + '.png';
  item.binary.data.mimeType = 'image/png';
}

return { json: item.json, binary: item.binary };

const allItems = $input.all();
const topic_id = allItems[0]?.json?.topic_id || '';

const images = {};
for (const item of allItems) {
  if (item.json) {
    const pos = item.json.position;
    images[pos] = item.json.imageUrl || item.json.url;
  }
}

return [{ json: {
  topic_id,
  imagen_hero_url: images['hero'] || '',
  imagen_body1_url: images['body_1'] || images['body1'] || '',
  imagen_body2_url: images['body_2'] || images['body2'] || '',
  imagen_body3_url: images['body_3'] || images['body3'] || '',
  imagen_body4_url: images['body_4'] || images['body4'] || '',
  images_count: allItems.length
} }];

